/*
** Self-contained AWS VPC model resource. Unlike the Azure resources (which
** extend an AutoGenerated.* namespace from codegen), AWS has no generated
** layer, so the interface, fields and factory are all defined inline here.
*/

import { OcdResources } from "../../../OcdDesign.js"
import { AwsResource } from "../AwsResource.js"

export interface AwsVpc extends AwsResource {
    cidrBlock: string
}

export namespace AwsVpc {
    export function newResource(type: string = 'vpc'): AwsVpc {
        return {
            ...AwsResource.newResource(type),
            cidrBlock: ''
        }
    }
    export function cloneResource(resource: AwsVpc, type: string = 'vpc'): AwsVpc {
        return AwsResource.cloneResource(resource, type) as AwsVpc
    }
    export function allowedParentTypes(): string[] {
        return []
    }
    export function getParentId(resource: AwsVpc): string {
        return resource.parentId
    }
    export function setParentId(resource: AwsVpc, parentId: string): AwsVpc {
        resource.parentId = parentId
        return resource
    }
    export function getConnectionIds(resource: AwsVpc, allResources: OcdResources): string[] {
        const associationIds: string[] = []
        return associationIds
    }
}

export class AwsVpcClient {
    static new(): AwsVpc {
        return AwsVpc.newResource()
    }
    static clone(resource: AwsVpc): AwsVpc {
        return AwsVpc.cloneResource(resource)
    }
}

export default AwsVpcClient
